from vex_sdk import VexClient
from azure.ai.projects import AgentSession

vex = VexClient(api_key="vex_azure_key")

def vex_middleware(agent_session: AgentSession, tool_call):
    if 'network_action' in tool_call.name:
        policy_result = vex.validate_policy(
            'cybersecurity_human_approval',
            {
                'action': tool_call.args,
                'severity': 'critical',
                'context': agent_session.thread.context
            }
        )
        if not policy_result.approved:
            return {'error': 'Human approval required for network isolation'}
    return tool_call

