import vex_sdk
from azure.ai.projects import AgentResponse

vex = vex_sdk.VexClient()

def validate_cve_advisory(response: AgentResponse):
    cves = vex_sdk.extract_entities(response.content, 'CVE')
    for cve in cves:
        validation = vex.enforce_policy(
            'cve_freshness_check',
            {'cve_id': cve, 'max_age_days': 30}
        )
        if not validation.valid:
            response.content += f"\n⚠️ CVE-{cve} requires manual verification: {validation.reason}"

import { VexClient } from '@vex-sdk/core';
import { AgentThread } from '@azure/ai-projects';

const vex = new VexClient({ apiKey: 'vex_azure_key' });

export async function tokenGuardrail(thread: AgentThread): Promise<string> {
  if (thread.tokenCount > 100000) {
    const summary = await vex.summarizeThread(thread.messages.slice(-50), {
      policy: 'cybersecurity_context_preservation',
      maxTokens: 8000
    });

    // Truncate and inject summary
    thread.messages = [{ role: 'system', content: `CONTEXT SUMMARY: ${summary}` }, ...thread.messages.slice(-10)];
    return 'Thread truncated with context summary - continuing investigation...';
  }
  return thread.content;
}
